namespace Store;

public sealed class ShoppingCart
{
    private readonly Dictionary<string, (int Quantity, decimal Price)> _items = new();
    private decimal _discountPercentage;

    public void AddItem(string sku, int quantity, decimal price)
    {
        ArgumentNullException.ThrowIfNull(sku);
        if (quantity <= 0)
            throw new ArgumentOutOfRangeException(nameof(quantity), "Quantity must be positive.");
        if (price < 0)
            throw new ArgumentOutOfRangeException(nameof(price), "Price cannot be negative.");

        if (_items.TryGetValue(sku, out var existing))
        {
            _items[sku] = (existing.Quantity + quantity, price);
        }
        else
        {
            _items[sku] = (quantity, price);
        }
    }

    public void RemoveItem(string sku)
    {
        ArgumentNullException.ThrowIfNull(sku);
        if (!_items.Remove(sku))
            throw new InvalidOperationException($"Item with SKU '{sku}' not found in cart.");
    }

    public decimal CalculateTotal()
    {
        decimal subtotal = _items.Values.Sum(item => item.Quantity * item.Price);
        return subtotal - (subtotal * _discountPercentage / 100m);
    }

    public void ApplyCoupon(string code)
    {
        ArgumentNullException.ThrowIfNull(code);
        _discountPercentage = code.ToUpperInvariant() switch
        {
            "SAVE10" => 10m,
            "SAVE20" => 20m,
            _ => throw new ArgumentException($"Unknown coupon code: '{code}'.", nameof(code))
        };
    }
}

using Microsoft.VisualStudio.TestTools.UnitTesting;
using Store;

namespace Store.Tests;

[TestClass]
public sealed class ShoppingCartTests
{
    private ShoppingCart _cart = null!;

    [TestInitialize]
    public void Setup()
    {
        _cart = new ShoppingCart();
    }

    // ───────────────────────────────────────────────
    // AddItem Tests
    // ───────────────────────────────────────────────

    [TestMethod]
    public void AddItem_SingleItem_IncreasesTotal()
    {
        // Arrange & Act
        _cart.AddItem("SKU-001", 2, 9.99m);

        // Assert
        Assert.AreEqual(19.98m, _cart.CalculateTotal());
    }

    [TestMethod]
    public void AddItem_MultipleDistinctItems_TotalIsSumOfAll()
    {
        // Arrange & Act
        _cart.AddItem("SKU-001", 1, 10.00m);
        _cart.AddItem("SKU-002", 3, 5.00m);

        // Assert
        Assert.AreEqual(25.00m, _cart.CalculateTotal());
    }

    [TestMethod]
    public void AddItem_DuplicateSku_UpdatesQuantity()
    {
        // Arrange
        _cart.AddItem("SKU-001", 2, 10.00m);

        // Act
        _cart.AddItem("SKU-001", 3, 10.00m);

        // Assert — quantity should be 2 + 3 = 5
        Assert.AreEqual(50.00m, _cart.CalculateTotal());
    }

    [TestMethod]
    public void AddItem_DuplicateSku_UpdatesPrice()
    {
        // Arrange
        _cart.AddItem("SKU-001", 2, 10.00m);

        // Act — adding same SKU with different price updates price
        _cart.AddItem("SKU-001", 1, 15.00m);

        // Assert — quantity = 3, price = 15.00
        Assert.AreEqual(45.00m, _cart.CalculateTotal());
    }

    [TestMethod]
    public void AddItem_NullSku_ThrowsArgumentNullException()
    {
        Assert.ThrowsException<ArgumentNullException>(() =>
            _cart.AddItem(null!, 1, 10.00m));
    }

    [TestMethod]
    [DataRow(0, DisplayName = "Zero quantity")]
    [DataRow(-1, DisplayName = "Negative quantity")]
    public void AddItem_InvalidQuantity_ThrowsArgumentOutOfRangeException(int quantity)
    {
        Assert.ThrowsException<ArgumentOutOfRangeException>(() =>
            _cart.AddItem("SKU-001", quantity, 10.00m));
    }

    [TestMethod]
    public void AddItem_NegativePrice_ThrowsArgumentOutOfRangeException()
    {
        Assert.ThrowsException<ArgumentOutOfRangeException>(() =>
            _cart.AddItem("SKU-001", 1, -5.00m));
    }

    [TestMethod]
    public void AddItem_ZeroPrice_Succeeds()
    {
        // Arrange & Act
        _cart.AddItem("FREE-ITEM", 1, 0.00m);

        // Assert
        Assert.AreEqual(0.00m, _cart.CalculateTotal());
    }

    // ───────────────────────────────────────────────
    // RemoveItem Tests
    // ───────────────────────────────────────────────

    [TestMethod]
    public void RemoveItem_ExistingItem_RemovesFromCart()
    {
        // Arrange
        _cart.AddItem("SKU-001", 2, 10.00m);
        _cart.AddItem("SKU-002", 1, 5.00m);

        // Act
        _cart.RemoveItem("SKU-001");

        // Assert
        Assert.AreEqual(5.00m, _cart.CalculateTotal());
    }

    [TestMethod]
    public void RemoveItem_OnlyItem_CartBecomesEmpty()
    {
        // Arrange
        _cart.AddItem("SKU-001", 2, 10.00m);

        // Act
        _cart.RemoveItem("SKU-001");

        // Assert
        Assert.AreEqual(0.00m, _cart.CalculateTotal());
    }

    [TestMethod]
    public void RemoveItem_NonExistentSku_ThrowsInvalidOperationException()
    {
        Assert.ThrowsException<InvalidOperationException>(() =>
            _cart.RemoveItem("DOES-NOT-EXIST"));
    }

    [TestMethod]
    public void RemoveItem_NullSku_ThrowsArgumentNullException()
    {
        Assert.ThrowsException<ArgumentNullException>(() =>
            _cart.RemoveItem(null!));
    }

    // ───────────────────────────────────────────────
    // CalculateTotal Tests
    // ───────────────────────────────────────────────

    [TestMethod]
    public void CalculateTotal_EmptyCart_ReturnsZero()
    {
        Assert.AreEqual(0.00m, _cart.CalculateTotal());
    }

    [TestMethod]
    public void CalculateTotal_MultipleItems_ReturnsSumOfQuantityTimesPrice()
    {
        // Arrange
        _cart.AddItem("A", 2, 10.00m);  // 20
        _cart.AddItem("B", 3, 7.50m);   // 22.50
        _cart.AddItem("C", 1, 100.00m); // 100

        // Assert
        Assert.AreEqual(142.50m, _cart.CalculateTotal());
    }

    [TestMethod]
    public void CalculateTotal_AfterRemovingItem_ExcludesRemovedItem()
    {
        // Arrange
        _cart.AddItem("A", 1, 50.00m);
        _cart.AddItem("B", 1, 30.00m);
        _cart.RemoveItem("A");

        // Assert
        Assert.AreEqual(30.00m, _cart.CalculateTotal());
    }

    // ───────────────────────────────────────────────
    // ApplyCoupon Tests
    // ───────────────────────────────────────────────

    [TestMethod]
    public void ApplyCoupon_Save10_Applies10PercentDiscount()
    {
        // Arrange
        _cart.AddItem("SKU-001", 1, 100.00m);

        // Act
        _cart.ApplyCoupon("SAVE10");

        // Assert
        Assert.AreEqual(90.00m, _cart.CalculateTotal());
    }

    [TestMethod]
    public void ApplyCoupon_Save20_Applies20PercentDiscount()
    {
        // Arrange
        _cart.AddItem("SKU-001", 1, 100.00m);

        // Act
        _cart.ApplyCoupon("SAVE20");

        // Assert
        Assert.AreEqual(80.00m, _cart.CalculateTotal());
    }

    [TestMethod]
    [DataRow("save10", DisplayName = "Lowercase save10")]
    [DataRow("Save10", DisplayName = "Mixed case Save10")]
    [DataRow("SAVE10", DisplayName = "Uppercase SAVE10")]
    public void ApplyCoupon_CaseInsensitive_AppliesDiscount(string code)
    {
        // Arrange
        _cart.AddItem("SKU-001", 1, 100.00m);

        // Act
        _cart.ApplyCoupon(code);

        // Assert
        Assert.AreEqual(90.00m, _cart.CalculateTotal());
    }

    [TestMethod]
    public void ApplyCoupon_UnknownCode_ThrowsArgumentException()
    {
        Assert.ThrowsException<ArgumentException>(() =>
            _cart.ApplyCoupon("INVALID"));
    }

    [TestMethod]
    public void ApplyCoupon_NullCode_ThrowsArgumentNullException()
    {
        Assert.ThrowsException<ArgumentNullException>(() =>
            _cart.ApplyCoupon(null!));
    }

    [TestMethod]
    public void ApplyCoupon_WithMultipleItems_DiscountsEntireTotal()
    {
        // Arrange
        _cart.AddItem("A", 2, 25.00m);  // 50
        _cart.AddItem("B", 1, 50.00m);  // 50
        // Subtotal = 100

        // Act
        _cart.ApplyCoupon("SAVE20");

        // Assert — 20% off 100 = 80
        Assert.AreEqual(80.00m, _cart.CalculateTotal());
    }

    [TestMethod]
    public void ApplyCoupon_ReplacedBySecondCoupon_UsesLatestDiscount()
    {
        // Arrange
        _cart.AddItem("SKU-001", 1, 100.00m);
        _cart.ApplyCoupon("SAVE10");

        // Act — apply a second coupon, should replace the first
        _cart.ApplyCoupon("SAVE20");

        // Assert
        Assert.AreEqual(80.00m, _cart.CalculateTotal());
    }

    [TestMethod]
    public void ApplyCoupon_EmptyCart_TotalRemainsZero()
    {
        // Act
        _cart.ApplyCoupon("SAVE10");

        // Assert
        Assert.AreEqual(0.00m, _cart.CalculateTotal());
    }

    // ───────────────────────────────────────────────
    // Integration / Combined Scenarios
    // ───────────────────────────────────────────────

    [TestMethod]
    public void FullWorkflow_AddRemoveApplyCoupon_CalculatesCorrectly()
    {
        // Arrange
        _cart.AddItem("WIDGET", 3, 10.00m);   // 30
        _cart.AddItem("GADGET", 2, 25.00m);   // 50
        _cart.AddItem("DOOHICKEY", 1, 20.00m); // 20
        // Subtotal = 100

        // Act
        _cart.RemoveItem("DOOHICKEY"); // Subtotal = 80
        _cart.ApplyCoupon("SAVE10");   // 10% off 80 = 72

        // Assert
        Assert.AreEqual(72.00m, _cart.CalculateTotal());
    }

    [TestMethod]
    public void AddItem_ThenRemoveAll_TotalIsZero()
    {
        // Arrange
        _cart.AddItem("A", 1, 10.00m);
        _cart.AddItem("B", 1, 20.00m);

        // Act
        _cart.RemoveItem("A");
        _cart.RemoveItem("B");

        // Assert
        Assert.AreEqual(0.00m, _cart.CalculateTotal());
    }
}

