         _cart.AddItem("WIDGET", 3, 10.00m);   // 30
         _cart.AddItem("GADGET", 2, 25.00m);   // 50
         _cart.AddItem("DOOHICKEY", 1, 20.00m); // 20
         // Subtotal = 100

         // Act
         _cart.RemoveItem("DOOHICKEY"); // Subtotal = 80
         _cart.ApplyCoupon("SAVE10");   // 10% off 80 = 72

